exercises.solution_code:
#include <iostream>

int main() {
    int value {};
    std::cin >> value;

    int copy { value };   // independent copy
    int& ref { value };   // alias for value

    ref += 10;            // modifies value through the reference

    std::cout << "ref: " << ref << '\n';
    std::cout << "copy: " << copy << '\n';
    std::cout << "same_object: true\n";

    return 0;
}

