exercises.solution_code:
#include <iostream>

int main() {
    int a {}, b {};
    std::cin >> a >> b;

    double d { a + 0.5 };

    int& refA { a };
    double& refD { d };

    refA *= b;

    std::cout << "a: " << a << " size: " << sizeof(a) << '\n';
    std::cout << "b: " << b << " size: " << sizeof(b) << '\n';
    std::cout << "d: " << d << " size: " << sizeof(d) << '\n';
    std::cout << "refA: " << refA << " size: " << sizeof(refA) << '\n';
    std::cout << "refD: " << refD << " size: " << sizeof(refD) << '\n';

    return 0;
}
